SELECT COUNT(*) AS total_unresolved_critical_exceptions
FROM exceptions
WHERE severity = 'critical' AND resolved = 0;

SELECT COUNT(alert_id) AS resolved_alerts_count
FROM alerts
WHERE status = 'resolved' AND user_id = 1;

SELECT AVG(julianday(e.resolution_date) - julianday(e.timestamp)) AS avg_resolution_time
FROM exceptions e
WHERE e.resolved = 1 AND e.resolution_date IS NOT NULL AND e.timestamp IS NOT NULL;
